// Query Supabase for active work item links
// that have Odoo tasks to check for completion
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const response = await this.helpers.request({
  method: 'GET',
  url: `${supabaseUrl}/rest/v1/work_item_links?sync_state=eq.ok&odoo_task_id=not.is.null&select=*`,
  headers: {
    'apikey': supabaseKey,
    'Authorization': `Bearer ${supabaseKey}`
  }
});

const links = JSON.parse(response);
return links.map(link => ({ json: link }));

